import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

// ✅ Supabase Bağlantı Bilgileri
const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey =
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";

const supabase = createClient(supabaseUrl, supabaseKey);

// ✅ Supabase'deki Kolon Sıralaması
const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER",
];

// ✅ Sadece Bu Projeler Gösterilecek
const ALLOWED_PROJECTS = new Set([
    "BUNGE LÜLEBURGAZ FTL",
    "REKA FTL",
    "EKSUN GIDA FTL",
    "SARUHAN FTL",
    "PEPSİ FTL",
    "MUTLU MAKARNA SPOT FTL",
    "TEKİRDAĞ UN FTL",
    "AYDINLI MODA FTL",
    "ADKOTURK FTL",
    "ADKOTURK FTL ENERJİ İÇECEĞİ",
    "SGS FTL",
    "BSH FTL",
    "ALTERNA GIDA FTL",
    "DERYA OFİS FTL",
    "SAPRO FTL",
    "MARMARA CAM FTL",
    "FAKİR FTL",
    "MODERN KARTON FTL",
    "KÜÇÜKBAY FTL",
]);

function App() {
    const [supabaseData, setSupabaseData] = useState([]);
    const [odakData, setOdakData] = useState([]);
    const [mergedData, setMergedData] = useState([]);

    // ✅ Supabase Verisini Çek
    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setSupabaseData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    // ✅ Odak Verisini Çek
    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization:
                            "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75",
                    },
                    body: JSON.stringify(payload),
                });

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                const validItems = items.filter(
                    (item) =>
                        item.OrderStatu !== 200 &&
                        item.TMSVehicleRequestDocumentNo &&
                        item.ProjectName &&
                        ALLOWED_PROJECTS.has(item.ProjectName)
                );

                const projectMap = new Map();

                validItems.forEach((item) => {
                    const project = item.ProjectName;
                    const despatch = !!item.TMSDespatchDocumentNo;
                    const vehicleNo = item.TMSVehicleRequestDocumentNo;
                    const key = `${project}-${vehicleNo}`;

                    if (!projectMap.has(project)) {
                        projectMap.set(project, {
                            ProjectName: project,
                            Talep: 0,
                            Tedarik: 0,
                            Verilemeyen: 0,
                            _seenKeys: new Set(),
                        });
                    }

                    const projData = projectMap.get(project);
                    if (!projData._seenKeys.has(key)) {
                        projData._seenKeys.add(key);
                        projData.Talep += 1;
                        despatch ? projData.Tedarik++ : projData.Verilemeyen++;
                    }
                });

                const finalData = Array.from(projectMap.values()).map((p) => {
                    delete p._seenKeys;
                    return p;
                });

                setOdakData(finalData);
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);

    // ✅ Supabase + Odak Verilerini Birleştir
    useEffect(() => {
        if (!supabaseData.length) return;

        const map = new Map();

        supabaseData.slice(1).forEach((row) => {
            const project = row["PROJE ADI"];
            map.set(project, { project, supabase: row });
        });

        odakData.forEach((odak) => {
            const project = odak.ProjectName;
            if (!map.has(project)) {
                map.set(project, { project });
            }
            map.get(project).odak = odak;
        });

        setMergedData(Array.from(map.values()));
    }, [supabaseData, odakData]);

    return (
        <div className="app-container">
            <h2>📊 Birleşik Tablo: Supabase 🟢 + Odak 🔵</h2>
            {mergedData.length > 0 ? (
                <div className="table-wrapper">
                    <table className="styled-table">
                        <thead>
                            <tr>
                                {columnOrder.map((col) => (
                                    <th key={col}>🟢 {col}</th>
                                ))}
                                <th>🔵 Talep</th>
                                <th>🔵 Tedarik</th>
                                <th>🔵 Verilemeyen</th>
                            </tr>
                        </thead>
                        <tbody>
                            {mergedData.map((row, idx) => {
                                const s = row.supabase || {};
                                const o = row.odak || {};
                                return (
                                    <tr key={idx}>
                                        {columnOrder.map((col) => {
                                            let val = s[col];
                                            if (col === "TED. %" && val) {
                                                const pct = Math.round(parseFloat(val) * 100);
                                                val = isNaN(pct) ? "-" : `%${pct}`;
                                            }
                                            if (
                                                ["HEDEF ÜSTÜ SEFER", "HEDEF ALTI SEFER", "HEDEF SEFER"].includes(col)
                                            ) {
                                                const num = parseFloat(val);
                                                if (!isNaN(num)) val = `${num.toLocaleString("tr-TR")} ₺`;
                                            }
                                            return <td key={col}>{val ?? "-"}</td>;
                                        })}
                                        <td>{o?.Talep ?? "-"}</td>
                                        <td style={{ color: "#27ae60", fontWeight: "bold" }}>{o?.Tedarik ?? "-"}</td>
                                        <td style={{ color: "#e74c3c", fontWeight: "bold" }}>{o?.Verilemeyen ?? "-"}</td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            ) : (
                <p>Veriler yükleniyor...</p>
            )}
        </div>
    );
}

export default App;
